# Expression evaluator using classes and inheritance
# Demonstrates: classes, polymorphism, enums, and isinstance checks

# Enum for operation types
enum OpType:
    ADD = 1
    SUB = 2
    MUL = 3
    DIV = 4

# Base class for expressions
class Expr:
    pass

# Number expression - holds a float value
class Number(Expr):
    value: float

    def __init__(self, value: float):
        self.value = value

# Variable expression - holds a variable name
class Variable(Expr):
    name: str

    def __init__(self, name: str):
        self.name = name

# Unary negation expression
class Negate(Expr):
    inner: Expr

    def __init__(self, inner: Expr):
        self.inner = inner

# Binary operation expression
class Binary(Expr):
    left: Expr
    op: OpType
    right: Expr

    def __init__(self, left: Expr, op: OpType, right: Expr):
        self.left = left
        self.op = op
        self.right = right

# Conditional expression
class Conditional(Expr):
    condition: Expr
    if_true: Expr
    if_false: Expr

    def __init__(self, condition: Expr, if_true: Expr, if_false: Expr):
        self.condition = condition
        self.if_true = if_true
        self.if_false = if_false

# Context for variable lookup
class EvalContext:
    vars: dict[str, float]

    def __init__(self):
        self.vars = {}

    def set(self, name: str, value: float) -> None:
