    def get(self, name: str) -> float !str:
        if name in self.vars:
            return Ok(self.vars[name])
        return Err(f"Unknown variable: {name}")

# Expression evaluator using isinstance and polymorphism
def eval_expr(e: Expr, ctx: EvalContext) -> float !str:
    if isinstance(e, Number):
        return Ok(e.value)

    if isinstance(e, Variable):
        return ctx.get(e.name)

    if isinstance(e, Negate):
        inner_result = eval_expr(e.inner, ctx)
        if inner_result.is_ok():
            v = inner_result.unwrap()
            return Ok(-v)
        else:
            return inner_result

    if isinstance(e, Binary):
        # Evaluate left and right
        left_result = eval_expr(e.left, ctx)
        right_result = eval_expr(e.right, ctx)

        # Check left for error
        if left_result.is_err():
            return left_result

        # Check right for error
        if right_result.is_err():
            return right_result

        # Both are Ok, extract values
        lv = left_result.unwrap()
        rv = right_result.unwrap()

        # Perform operation based on op type
        if e.op == OpType.ADD:
            return Ok(lv + rv)
        elif e.op == OpType.SUB:
            return Ok(lv - rv)
        elif e.op == OpType.MUL:
            return Ok(lv * rv)
        elif e.op == OpType.DIV:
            if rv == 0.0:
                return Err("Division by zero")
            return Ok(lv / rv)
        else:
            return Err("Unknown operator")

    if isinstance(e, Conditional):
